head.script:
//-------------------------------------------------------------------------
// 만기예정일자 기간을 구한다.
//-------------------------------------------------------------------------
scwin.strFromDate = $c.date.getServerDateTime("yyyyMM")+"01";
scwin.strToDate = $c.date.getServerDateTime("yyyyMMdd");// 현재일자를 구한다.
scwin.memJson = $c.data.getMemInfo();
scwin.privAdmin = $c.data.getMemInfo("privAdmin");

//-------------------------------------------------------------------------
// 로그인 정보 전역 변수를 선언
//-------------------------------------------------------------------------
scwin.G_acctDeptCd = $c.data.getMemInfo("acctDeptCd");
scwin.G_acctDeptNm = $c.data.getMemInfo("acctDeptNm");
scwin.G_empNo = $c.data.getMemInfo("empNo");
scwin.G_empNm = $c.data.getMemInfo("userNm");

scwin.vUserHomeClsCd = $c.data.getMemInfo("userHomeClsCd");// 사용자소속구분코드 
scwin.loginCoCd = $c.data.getMemInfo("coCd");
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.loginCoCd)?'':scwin.loginCoCd; // 소속 자회사
scwin.loginCoClsCd = $c.data.getMemInfo("coClsCd");
scwin.vLoginCoClsCd =$c.gus.cfIsNull(scwin.loginCoClsCd)?'': scwin.loginCoClsCd;  ;//회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.isSubCompany = false;
scwin.isStarted = true;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 처리)
//-------------------------------------------------------------------------
// 전역변수 선언
//--------------------------------------------------------------------fm_301_03_03b-----
scwin,wrkNo = "";				// 작업구분코드
scwin,fromDate = "";			// 작업날짜

//-------------------------------------------------------------------------
// hidden
//-------------------------------------------------------------------------
scwin.txtCoClsCd ="";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    //공통코드 적용
    const codeOptions = [
        { grpCd: "FM014", compID: "lc_billRecvAcctCd, acb_sbillRecvAcctCd,gr_billRecvDisho:billRecvAcctCd "},
        //{ grpCd: "FM014", compID: "gr_billRecvDisho:billRecvAcctCd"},
        { grpCd: "FM015", compID: "lc_billRecvStsCd,gr_billRecvDisho:billRecvStsCd"},
        { grpCd: "FM044", compID: "lc_mgntAcctRecvPatternCd"},
    ];
    $c.data.setCommonCode(codeOptions);
};
//-------------------------------------------------------------------------
// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
//-------------------------------------------------------------------------
scwin.ondataload = function() { 
    //공통코드재매핑.
    let dltStr = "dlt_commonCodeFM015"; // FM015 코드의 dataList
    let dlt = $c.gus.object(dltStr);
    $c.gus.copy(dltStr, "dlt_commonCodeFM015_1", true); // dlt_commonCodeFM015_1 으로 dataList 을 복사

    let dlt2 = $c.gus.object("dlt_commonCodeFM015_1"); // 객체화
    $c.data.dataListFilter(dlt2, "fltrCd1 == '10'");  // 새로운 데이터리스트에 필터 lc_sbillRecvStsCd GauceUtil.getCodeList("FM015",1,"10")
    acb_sbillRecvStsCd.setNodeSet("data:dlt_commonCodeFM015_1", "cdNm", "cd"); // selectBox 에 새로운 데이터리스트로 매핑
    acb_sbillRecvStsCd.addItem("전체", "-2", "data:dlt_commonCodeFM015_1", 0);

    acb_sbillRecvAcctCd.setSelectedIndex(0);
    acb_sbillRecvStsCd.setSelectedIndex(0);
	ed_FromDate.setValue(scwin.strFromDate);
    ed_ToDate.setValue(scwin.strToDate);
    $c.gus.cfDisableKeyData();
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {

    try {
        //사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
        if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
            scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
            scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
        }
        ed_coCd.setValue(scwin.vLoginCoCd);

        scwin.f_PopUpCompanyInfo('T');
    } catch (e) {
       console.log("f_setCompanyInfo: " +e);
    }
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function (pWinCloseTF) {
    /*
    var rtnList = cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
                                ,ed_coCd.text, txt_coNm.value
                                ,pWinCloseTF,null,null,null,null
                                ,null,null,null,null,null);
    */
    udc_coCd.setSelectId('retrieveDongbuGroupCompanyInfo');
    udc_coCd.cfCommonPopUp(scwin.udc_coCd_callBackFunc // 콜백 함수
                        , ed_coCd.getValue()              // 화면에서의  Code Element의 Value
                        , ed_coNm.getValue()              // 화면에서의  Name Element의 Value
                        , pWinCloseTF                     // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        ); 
};

//-------------------------------------------------------------------------
// 회사코드입력시
//-------------------------------------------------------------------------
scwin.udc_coCd_onblurCodeEvent = function (e) {
    scwin.isStarted = false;
    ed_coNm.setValue("");
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 회사코드 찾기버튼 클릭시
//-------------------------------------------------------------------------
scwin.udc_coCd_onclickEvent = function (e) {
    scwin.isStarted = false;
    scwin.f_PopUpCompanyInfo('F');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 콜백
//-------------------------------------------------------------------------
scwin.udc_coCd_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        // SET	 
        if(rtnList != null ) { 
            if (rtnList[0] == "N/A") return false;  
                if(ed_coCd.hidVal != rtnList[0] )
                    scwin.f_initObj();
                ed_coCd.setValue(rtnList[0]);	// 코드
                ed_coNm.setValue(rtnList[5]);	// 회사명
                ed_coCd.hidVal = rtnList[0];  // 히든값
                scwin.txtCoClsCd = rtnList[1];	// 회사구분  
        }else{
            ed_coCd.setValue("");	// 코드
            ed_coNm.setValue("");	// 회사명
            ed_coCd.hidVal = "";
            scwin.txtCoClsCd ="";	// 회사구분    
        }

        if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
            scwin.isSubCompany = true;
        }else{
            scwin.isSubCompany = false;
        }
        if ( scwin.isStarted == true ) {
            scwin.f_enableCompanyInfo();
            ed_sacctDeptCd.setValue(scwin.G_acctDeptCd);
            ed_sacctDeptCd.hidVal = scwin.G_acctDeptCd;
            ed_sacctDeptNm.setValue(scwin.G_acctDeptNm);
            ed_sacctDeptNm.hidVal = scwin.G_acctDeptNm;
            ed_sacctDeptCd.focus();
        }

    } catch (e) {
       console.log("udc_coCd_callBackFunc" + e);
    }
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 enable 처리
//-------------------------------------------------------------------------
scwin.f_enableCompanyInfo = function (e) {
    try{
        if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company ]);    
        }else {
            $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company  ]);   
        }
    } catch (e) {
       console.log("udc_coCd_callBackFunc" + e);
    }
};

//-------------------------------------------------------------------------
// 조회 및 마감확인시 작업코드 날짜 세팅하는 함수
//-------------------------------------------------------------------------
scwin.f_setWrkNoFromDate = function() {
    try{
        scwin.wrkNo = ACConstants.CLOSE_MONTH;
    } catch (e) {
       console.log("f_setWrkNoFromDate : " + e);
    }
};    

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    try{
        if (!$c.gus.cfIsAfterDate(ed_FromDate.getValue(),ed_ToDate.getValue())) {
            await $c.win.alert("조회 만기일자는 종료일자 보다 이전 날짜 이어야 합니다.");
            ed_FromDate.focus();
            return false;;
        }

        let ret = await $c.gus.cfValidate([ed_FromDate,ed_ToDate,ed_sacctDeptCd,ed_sclntNo]);
        if (!ret) {
            return false;
        }

        const params = {
            coClsCd  : scwin.txtCoClsCd,
        }
        //데이터셋에 정보설정
        ds_searchBillRecvDisho.setJSON(params);
        ds_billRecvDisho.removeAll();//정보삭제
        $c.sbm.execute(sbm_searchBillRecvDisho);

    } catch (e) {
       console.log("f_Retrieve : " + e);
    }
};

//-------------------------------------------------------------------------
// 조회결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_searchBillRecvDisho_submitdone = async function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

        tbx_totalRows.setValue($c.gus.cfInsertComma(ds_billRecvDisho.getRowCount()));
        if( ds_billRecvDisho.getRowCount() == 0 ){
            await $c.win.alert(MSG_CM_ERR_003);
        }else{

            scwin.gr_billRecvDisho_onrowindexchange(0);
            $c.gus.cfGoPrevPosition(gr_billRecvDisho, 0); //첫번째 row 포지션이동
            if (ds_billRecvDisho.getCellData(0, "billRecvStsCd")!= ACConstants.BILLRECV_DUE ) {
                $c.gus.cfDisableKeyData();
                $c.gus.cfDisableObjects([ed_slipDt,ed_procDt]);//cfDisableObjects([img1,img2]);
                scwin.f_enableCompanyInfo();
            }else{
                $c.gus.cfDisableKey();

			    $c.gus.cfEnableObjects([ed_slipDt,ed_procDt]);
            }
            scwin.f_enableCompanyInfo();
        }
    } catch (e) {
       console.log("sbm_searchBillRecvDuet_submitdone : " + e);
    }
}; 

//-------------------------------------------------------------------------
// 그리드정보와 입력정보 매핑
//-------------------------------------------------------------------------
scwin.gr_billRecvDisho_onrowindexchange = function (rowIndex, oldRow) {
    ds_billRecvDisho.setRowPosition(rowIndex);
};

scwin.f_initObj = function() {
    try{
        $c.gus.cfInitObjects([ed_sclntNo,ed_sclntNm]); //거래처
        $c.gus.cfInitObjects([ed_sacctDeptCd,ed_sacctDeptNm]); //부서
    } catch (e) {
       console.log("f_initObj >" + e);
    }
};

//-------------------------------------------------------------------------
// 마감체크
//-------------------------------------------------------------------------
scwin.f_JobCloseYN = async function(slipDt) {
    try{
        scwin.f_setWrkNoFromDate();

        let isClose = await udc_closeYn.cfJobCloseYN(
                        "CUR",
                        slipDt.substring(0,6),
                        "00",
                        scwin.wrkNo,
                        "0",
                        "ARR",
                        "N",
                        '');
        console.log("마감체크 : " + isClose);                

        // 마감작업 조회시 해당값이 없을경우 오류 발생
        if ( isClose[0] == "DNF" ) {
            $c.gus.cfAlertMsg("마감되었습니다.");
            return false;
        }

        // 선행마감 작업에 대한 검사
        if ( isClose[3] == "PRE" ) {
            if (isClose[0]=="1") {
                $c.gus.cfAlertMsg("선행작업 "+isClose[2]+"이 미마감되어서 현재 작업을 진행할 수 없습니다.");
                return false;
            } else if (isClose[0]=="0") {
                $c.gus.cfAlertMsg("선행작업 "+isClose[2]+"이 마감작업중이어서 현재 작업을 진행할 수 없습니다.");
                return false;
            } 
        } 

        // 해당마감 작업에 대한 검사
        if ( isClose[3] == "CUR" ) {
            if(isClose[0]=="0"){
                $c.gus.cfAlertMsg(isClose[2] + "(이)가 마감중입니다.");
                return false;
            }else if(isClose[0]=="2"){
                $c.gus.cfAlertMsg(isClose[2] + "(이)가 마감완료가 되었습니다");
                return false;
            }else {
                return true;
            }
        }

    } catch (e) {
       console.log("f_JobCloseYN : " + e);
    }
}; 

//-------------------------------------------------------------------------
// 그리드 클릭
//-------------------------------------------------------------------------
scwin.gr_billRecvDisho_oncellclick = async function (rowIndex, columnIndex, columnId) {
    try{
        let Colid = columnId;
        let Row = rowIndex;
        let i =0;

        if (ds_billRecvDisho.getCellData(Row,"billRecvStsCd") != ACConstants.BILLRECV_DUE &&
            ds_billRecvDisho.getCellData(Row,"billRecvStsCd") != ACConstants.BILLRECV_DRAFT_DC ) {
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableObjects([ed_slipDt,ed_procDt]);
            scwin.f_enableCompanyInfo();
        } else {
            $c.gus.cfDisableKey();
            $c.gus.cfEnableObjects([ed_slipDt,ed_procDt]);
        }
        scwin.f_enableCompanyInfo();

        // 전표번호 POPUP호출
        if ( Colid == "procSlipNo" ) {
            $c.gus.cfShowSlipInfo(ds_billRecvDisho.getCellData(Row,"procSlipNo"));
        }

        for (i=0; i< ds_billRecvDisho.getRowCount(); i++){

            if (ds_billRecvDisho.getCellData(Row,"dcYn") != ds_billRecvDisho.getCellData(i,"dcYn") && ds_billRecvDisho.getCellData(i,"num") == "T" && Colid == "num") {
                await $c.win.alert("분할 할인한 어음은 여러건을 한꺼번에 처리가 불가능합니다. ");
                ds_billRecvDisho.setCellData(Row,"num","F");
                return false;
            }	

            if (ds_billRecvDisho.getCellData(Row,"billRecvNo") == ds_billRecvDisho.getCellData(i,"billRecvNo") && Colid == "num") {
                ds_billRecvDisho.setCellData(Row,"num",ds_billRecvDisho.getCellData(Row,"num"));
            }
        }

    } catch (e) {
        console.log("gr_billRecvDisho_oncellclick : " + e);
    }
};

//-------------------------------------------------------------------------
// 전표일자 변경시
//-------------------------------------------------------------------------
scwin.ed_slipDt_onkeyup = function (e) {
    scwin.f_setChangePartDc("1");
};

//-------------------------------------------------------------------------
// 부도일자 변경시
//-------------------------------------------------------------------------
scwin.ed_procDt_onkeyup = function (e) {
    scwin.f_setChangePartDc("2");
};

//-------------------------------------------------------------------------
// 채권유형 변경시
//-------------------------------------------------------------------------
scwin.lc_mgntAcctRecvPatternCd_onchange = function (info) {
    scwin.f_setChangePartDc("3");
};

//-------------------------------------------------------------------------
// 부분할인건의 전표일자, 부도일자, 관리채권유형 변경시 모두 변경하는 함수
//-------------------------------------------------------------------------
scwin.f_setChangePartDc = function (chk) {
    try{
        if (ds_billRecvDisho.getCellData(ds_billRecvDisho.getRowPosition(),"dcYn")=="1") {
            for (i=0; i< ds_billRecvDisho.getRowCount(); i++){
                if (chk == "1" && ds_billRecvDisho.getCellData(i, "num") == "T") {
                    ds_billRecvDisho.setCellData(i, "slipDt",ed_slipDt.getValue());   
                } else if (chk == "2" && ds_billRecvDisho.getCellData(i, "num") == "T") {
                    ds_billRecvDisho.setCellData(i, "procDt",ed_procDt.getValue());   
                } else if (chk == "3" && ds_billRecvDisho.getCellData(i, "num") == "T") { 
                    ds_billRecvDisho.setCellData(i, "mgntAcctRecvPatternCd",lc_mgntAcctRecvPatternCd.getValue());   
                }
            }
        }
    } catch (e) {
        console.log("f_setChangePartDc : " + e);
    }
};

//-------------------------------------------------------------------------
// 거래처코드
//-------------------------------------------------------------------------
scwin.udc_clntNo_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_sclntNo, ed_sclntNm,'2','CD');
};

//-------------------------------------------------------------------------
// 거래처명
//-------------------------------------------------------------------------
scwin.udc_clntNo_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_sclntNo, ed_sclntNm,'2','NM');
};

//-------------------------------------------------------------------------
// 거래처찾기
//-------------------------------------------------------------------------
scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_sclntNo,ed_sclntNm,'2','ALL');
};

//-------------------------------------------------------------------------
// 부서코드
//-------------------------------------------------------------------------
scwin.udc_acctDeptCd_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_sacctDeptCd,ed_sacctDeptNm,'1','CD');
};
//-------------------------------------------------------------------------
// 부서명
//-------------------------------------------------------------------------
scwin.udc_acctDeptCd_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_sacctDeptCd,ed_sacctDeptNm ,'1','NM');
};
//-------------------------------------------------------------------------
// 부서찾기
//-------------------------------------------------------------------------
scwin.udc_acctDeptCd_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_sacctDeptCd,ed_sacctDeptNm,'1','ALL');
};

//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
// flag값이 CD:코드변경이 없으면 POPUP안뛰움, NM:무조건 POPUP뛰움
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
    try{
        if ( flag == "CD") {
            if (orgObjCd.getValue() == orgObjCd.hidVal) {
                return false;
            }else{
                orgObjNm.setValue("");
            }
        }else{
            if (orgObjNm.getValue() == orgObjNm.hidVal) {
                return false;
            }else{
                orgObjNm.setValue("");
            }
        }

        if (orgObjCd.getValue().trim() != "" || flag == "NM") {
            if (orgObjNm.getValue().trim() != "" || flag == "CD") {
                orgObjCd.setValue(orgObjCd.getValue().trim());
                orgObjNm.setValue(orgObjNm.getValue().trim());
                scwin.f_openPopUp(orgObjCd, orgObjNm, select_code,"NO");
            }
        } else {
            orgObjNm.setValue("");
            orgObjCd.setValue("");
            orgObjCd.hidVal = "";
        }

    } catch (e) {
       console.log("f_CheckPopUp : " + e);
    }
};

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->수금부서 , 2:조회->거래처
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
    try {
        let cd ='';
        let nm ='';
        let param ='';

        // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
        // 넘어온 OBJ가 EMEdit인지 TextBox인지 구분한다.
        // flag:SKIP일경우는 Tag에 대한 속성 검사를 하지 않는다.
        if ( flag != "SKIP") {
            if (flag == "ALL") {
                cd = "";
                nm = "";
            } else {
                cd = orgObjCd.getValue();
                nm = orgObjNm.getValue();
            }
        } else {
            cd = orgObjCd;
            nm = "";
        }

        switch (select_code) {
            // 조회조건용 수금부서 PopUp 호출
  		    case '1' :
                param    = ","+ ed_coCd.getValue()+","+scwin.txtCoClsCd; //자회사 회계시스템 추가사항
                //rtnList = cfCommonPopUp('retrieveAcctDeptCdInfo6',cd,nm,"T",null,null,null,null,param,"450","500",null,null);  // 수금부서
                udc_acctDeptCd.setSelectId('retrieveAcctDeptCdInfo6');
                udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callBackFunc // 콜백 함수
                        , cd                              // 화면에서의  Code Element의 Value
                        , nm                              // 화면에서의  Name Element의 Value
                        , "T"                             // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , param                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , "450"                           // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , "500"                           // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );
                break;
            // 조회조건용 거래처 PopUp 호출
  		    case '2' :
                param    = ",,,"+ed_coCd.getValue();	//자회사 회계시스템 추가사항
                //rtnList = cfCommonPopUp('retrieveClntList',cd,nm,"T",null,null,null,null,param,null,null,null,null); // 거래처
                udc_clntNo.setSelectId('retrieveClntList');
                udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc // 콜백 함수
                        , cd                              // 화면에서의  Code Element의 Value
                        , nm                              // 화면에서의  Name Element의 Value
                        , "T"                             // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , param                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );     
                break;    
        }

    } catch (e) {
       console.log("f_openPopUp : " + e);
    }
};


//-------------------------------------------------------------------------
// 부서 PopUp 콜백
//-------------------------------------------------------------------------
scwin.udc_acctDeptCd_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if (rtnList != null ) {
			if (rtnList[0] == "N/A") return;
			ed_sacctDeptCd.setValue(rtnList[0]);	// 코드값
			ed_sacctDeptNm.setValue(rtnList[1]);	// 코드명
            ed_sacctDeptCd.hidVal = rtnList[0];	// HIDDEN 코드값
            ed_sacctDeptNm.hidVal = rtnList[1];	// HIDDEN 코드값
		} else {
			ed_sacctDeptCd.setValue("");
			ed_sacctDeptNm.setValue("");
            ed_sacctDeptCd.hidVal = "";
            ed_sacctDeptNm.hidVal = "";
		}

    } catch (e) {
       console.log("udc_acctDeptCd_callBackFunc " + e);
    }
};

