//-------------------------------------------------------------------------
// 부도처리시 호출 되는 함수
//-------------------------------------------------------------------------
scwin.f_Save = async function (chk) {
    try{
        let checkCount = 0;
        let chk0DcYn = 0;
        let chk1DcYn = 0;
        let chkBillRecvNo = "";

        // 어음상태가 수금이 것만 부도처리가 가능함.
        for (i=0; i< ds_billRecvDisho.getRowCount(); i++){
            if ( ds_billRecvDisho.getCellData(i,"billRecvStsCd") != ACConstants.BILLRECV_DUE &&
                ds_billRecvDisho.getCellData(i,"billRecvStsCd") != ACConstants.BILLRECV_DRAFT_DC &&
			    ds_billRecvDisho.getCellData(i,"num") == "T") {
                await $c.win.alert("이미 부도처리한 어음이 선택되었습니다.");
                ds_billRecvDisho.setRowPosition(i);
                return false;
            }
            if ( ds_billRecvDisho.getCellData(i,"bfBillRecvMgntNo") != "" && ds_billRecvDisho.getCellData(i,"num") == "T" ) {

                await $c.win.alert("지급 처리한 어음이 선택되었습니다. 지급 취소 후 부도처리 하세요.");
                ds_billRecvDisho.setRowPosition(i);
                return false;
            }

            // Check 여부 카운트
            if ( ds_billRecvDisho.getCellData(i,"num") == "T" ) {
                // 마감여부 확인
                let jobCloseYN  = await scwin.f_JobCloseYN(ds_billRecvDisho.getCellData(i,"slipDt"));
                if ( !jobCloseYN ) {
                    return false;
                }

                if ( ds_billRecvDisho.getCellData(i,"dcYn") == 1) {
                    if (chk1DcYn == 0) {
                        chkBillRecvNo = ds_billRecvDisho.getCellData(i,"billRecvNo");
                    }
                    if (chkBillRecvNo != ds_billRecvDisho.getCellData(i,"billRecvNo")) {
                        await $c.win.alert("분할할인처리한 어음은 같이 처리 할 수 없습니다.");
                        return false;
                    }
                    chk1DcYn++;				
                } else {
                    chk0DcYn++;
                }
                checkCount++;
            }else{
                ds_billRecvDisho.undoRow(i);//ds_billRecvDisho.Undo(i);
            }

            if ( ds_billRecvDisho.getCellData(i,"billRecvStsCd") == ACConstants.BILLRECV_DRAFT_DC && 
		        ds_billRecvDisho.getCellData(i,"procDt") < ds_billRecvDisho.getCellData(i,"dueDt") &&
		        ds_billRecvDisho.getCellData(i,"payInterest") < 1 && ds_billRecvDisho.getCellData(i,"num") == "T") {
		     	await $c.win.alert("어음상태가 할인이고 부도일이 만기일 이전 이면 환출이자를 입력하셔야 합니다.");
		     	return false;
		     }
        }//for

        // 필수입력 여부 Check
        let ret = await $c.gus.cfValidate([gr_billRecvDisho]);
        if (!ret) {
            return false;
        }
        /*let ret = await $c.gus.cfValidate([gr_billRecvDisho]);
        if (!ret) {
            return false;
        }
        TOBE 그리드에 포커스 이동할 정보가 없어서 loop로 변경체크
        */
        /*for (i=0; i< ds_billRecvDisho.getRowCount(); i++){
            if ( ds_billRecvDisho.getCellData(i,"num") == "T" ) {
                if (ds_billRecvDisho.getCellData(i,"procDt") == ""){
                    await $c.win.alert("처리일자는 필수 입력 항목 입니다.");
                    ds_billRecvDisho.setRowPosition(i);
                    $c.gus.cfGoPrevPosition(gr_billRecvDisho, i); //포지션이동
                    ed_prtDt.focus();
		     	    return false;
                }

                if (ds_billRecvDisho.getCellData(i,"slipDt") == ""){
                    await $c.win.alert("전표일자는 필수 입력 항목 입니다.");
                    ds_billRecvDisho.setRowPosition(i);
                    $c.gus.cfGoPrevPosition(gr_billRecvDisho, i); //포지션이동
                    ed_slipDt.focus();
		     	    return false;
                }

                if (ds_billRecvDisho.getCellData(i,"mgntAcctRecvPatternCd") == ""){
                    await $c.win.alert("관리채권유형은 필수 입력 항목 입니다.");
                    ds_billRecvDisho.setRowPosition(i);
                    $c.gus.cfGoPrevPosition(gr_billRecvDisho, i); //포지션이동
                    lc_mgntAcctRecvPatternCd.focus();
		     	    return false;
                }
            }
        }*/

        // 선택사항이 있는지 유무 검사
        if ( checkCount == 0 ) {
            await $c.win.alert("선택하신 사항이 없습니다.");
            return false;
        }

        if ( chk0DcYn > 0 && chk1DcYn > 0 ) {
            await $c.win.alert("분할할인처리한 어음은 같이 처리 할 수 없습니다.");
            return false;
        }

        if ( chk0DcYn > 0 && chk1DcYn > 0 ) {
            await $c.win.alert("분할할인처리한 어음은 같이 처리 할 수 없습니다.");
            return false;
        }

        if(await $c.win.confirm("선택하신 사항을 부도처리 하시겠습니까?")) {
            sbm_saveBillRecvDisho.action = "/ac.fm.collmoneymgnt.billrecv.ProcessDishonorCMD.do";
            $c.sbm.execute(sbm_saveBillRecvDisho);
        }

    } catch (e) {
        console.log("f_Save : " + e);
    }
};

//-------------------------------------------------------------------------
// 부도처리 취소시 호출 되는 함수
//-------------------------------------------------------------------------
scwin.f_Cancel = async function (chk) {
    try{
        let checkCount = 0;
        let i = 0;    

        // 어음상태가 부도인 것만 부도취소가 가능함.
        for (i=0; i< ds_billRecvDisho.getRowCount(); i++){
            if ( ds_billRecvDisho.getCellData(i,"billRecvStsCd") != ACConstants.BILLRECV_DISHO &&
			    ds_billRecvDisho.getCellData(i,"num") == "T") {
                await $c.win.alert("상태가 부도인것만 부도취소가 가능합니다.");
                ds_billRecvDisho.setRowPosition(i);
                return false;
            }
            // Check 여부 카운트
            if ( ds_billRecvDisho.getCellData(i,"num") == "T" ) {
                checkCount++;
            }else{
                ds_billRecvDisho.undoRow(i);//ds_billRecvDisho.Undo(i);
            }
        }

        // 선택사항이 있는지 유무 검사
        if ( checkCount == 0 ) {
            await $c.win.alert("선택하신 사항이 없습니다.");
            return false;
        }

        if(await $c.win.confirm("현재 선택하신 부도어음을 부도취소 하시겠습니까?")) {
            sbm_saveBillRecvDisho.action = "/ac.fm.collmoneymgnt.billrecv.CancelDishonorProcessCMD.do";
            $c.sbm.execute(sbm_saveBillRecvDisho);
        }

    } catch (e) {
        console.log("f_Cancel : " + e);
    }
};

//-------------------------------------------------------------------------
// 부도처리시/부도처리 취소 콜백
//-------------------------------------------------------------------------
scwin.sbm_saveBillRecvDisho_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.f_Retrieve();
};
